// ---------- cpu-worker.js ----------
var parentPort = require("worker_threads").parentPort;

parentPort.on("message", function(data) {
  // CPU-intensive: Fibonacci calculation
  function fib(n) {
    if (n <= 1) return n;
    return fib(n - 1) + fib(n - 2);
  }

  var results = data.numbers.map(function(n) {
    return { input: n, result: fib(40 + n) };
  });

  parentPort.postMessage({ type: "result", data: results });
});

// main.js
var Worker = require("worker_threads").Worker;

// Shared counter in shared memory
var sab = new SharedArrayBuffer(4 * 4); // 4 int32 slots
var counter = new Int32Array(sab);
counter[0] = 0; // task counter
counter[1] = 0; // completed counter

var worker = new Worker("./shared-worker.js");

// Transfer SharedArrayBuffer (zero-copy)
worker.postMessage({ sab: sab }, [sab]);

// Main thread updates counter
Atomics.add(counter, 0, 10); // Add 10 tasks

// Wait for worker to complete all tasks
Atomics.wait(counter, 1, 0); // Wait until completed !== 0
console.log("All tasks completed:", Atomics.load(counter, 1));

worker.terminate();

// ---------- shared-worker.js ----------
var parentPort = require("worker_threads").parentPort;

parentPort.on("message", function(msg) {
  var sab = msg.sab;
  var counter = new Int32Array(sab);

  // Read total tasks
  var total = Atomics.load(counter, 0);

  // Process tasks
  for (var i = 0; i < total; i++) {
    // Simulate work
    Atomics.add(counter, 1, 1); // Increment completed
  }

  // Notify main thread
  Atomics.notify(counter, 1, 1);
});

var Worker = require("worker_threads").Worker;
var os = require("os");

function WorkerPool(workerFile, poolSize) {
  this.workers = [];
  this.queue = [];
  this.activeCount = 0;

  for (var i = 0; i < (poolSize || os.cpus().length - 1); i++) {
    this._addWorker(workerFile);
  }
}

WorkerPool.prototype._addWorker = function(workerFile) {
  var worker = new Worker(workerFile);
  var self = this;

  worker.on("message", function(result) {
    self.activeCount--;
    if (worker._currentResolve) {
      worker._currentResolve(result);
      worker._currentResolve = null;
    }
    self._processQueue(worker);
  });

  worker.on("error", function(err) {
    self.activeCount--;
    if (worker._currentReject) {
      worker._currentReject(err);
      worker._currentReject = null;
    }
    self._addWorker(workerFile); // Replace failed worker
  });

  this.workers.push(worker);
};

WorkerPool.prototype.exec = function(data) {
  var self = this;
  return new Promise(function(resolve, reject) {
    self.queue.push({ data: data, resolve: resolve, reject: reject });
    self._processNext();
  });
};

WorkerPool.prototype._processNext = function() {
  if (this.queue.length === 0) return;
  for (var i = 0; i < this.workers.length; i++) {
    var w = this.workers[i];
    if (!w._currentResolve) {
      var task = this.queue.shift();
      w._currentResolve = task.resolve;
      w._currentReject = task.reject;
      w.postMessage(task.data);
      this.activeCount++;
      return;
    }
  }
};

// Usage
var pool = new WorkerPool("./task-worker.js", 4);
pool.exec({ numbers: [1,2,3] }).then(function(result) {
  console.log("Task result:", result);
});

// main.js
var Worker = require("worker_threads").Worker;

// Create a large buffer
var size = 100 * 1024 * 1024; // 100MB
var buffer = new ArrayBuffer(size);
var view = new Uint8Array(buffer);
for (var i = 0; i < size; i++) {
  view[i] = i % 256;
}

console.log("Buffer size:", buffer.byteLength, "bytes");

var worker = new Worker("./transfer-worker.js");

// WITHOUT transfer: copies the data (slow, 100MB copy)
// WITH transfer: moves ownership (fast, 0-copy)
worker.postMessage({ data: buffer }, [buffer]);

// After transfer, buffer is neutered (cannot be used)
console.log("Buffer after transfer:", buffer.byteLength); // 0

worker.on("message", function(msg) {
  console.log("Worker processed:", msg.result);
});

// ---------- transfer-worker.js ----------
var parentPort = require("worker_threads").parentPort;

parentPort.on("message", function(msg) {
  var buffer = msg.data;
  var view = new Uint8Array(buffer);

  // Modify data in place
  var sum = 0;
  for (var i = 0; i < view.length; i++) {
    sum += view[i];
    view[i] = 255 - view[i];
  }

  // Send back the modified buffer
  parentPort.postMessage({ result: sum, data: buffer }, [buffer]);
});

// main.js
var Worker = require("worker_threads").Worker;

var worker = new Worker("./resource-worker.js", {
  resourceLimits: {
    maxOldGenerationSizeMb: 50,  // Max heap size: 50MB
    maxYoungGenerationSizeMb: 10,
    codeRangeSizeMb: 5,
    stackSizeMb: 1
  }
});

worker.on("error", function(err) {
  console.error("Worker error (may exceed limits):", err.message);
});

worker.on("exit", function(code) {
  console.log("Worker exited with code:", code);
});

worker.postMessage({ action: "allocate", size: 30 * 1024 * 1024 });

// ---------- resource-worker.js ----------
var parentPort = require("worker_threads").parentPort;

parentPort.on("message", function(msg) {
  if (msg.action === "allocate") {
    // This may fail if it exceeds maxOldGenerationSizeMb
    try {
      var buffer = Buffer.alloc(msg.size);
      buffer.fill(1);
      parentPort.postMessage({ status: "ok", size: buffer.length });
    } catch (err) {
      parentPort.postMessage({ status: "error", error: err.message });
    }
  }
});
